## Algorithm

```typescript
function trustScore(address, context) {
  const kept   = commitments.filter(c => c.status === 'kept').length;
  const broken = commitments.filter(c => c.status === 'broken').length;
  const ratio  = kept / (kept + broken) || 0.5;

  const vouchW = vouches.reduce((s, v) =>
    s + trustScore(v.voucher, context) * v.weight, 0);

  const tenure = Math.min(Math.log(daysActive + 1) / Math.log(365), 1.0);

  return 0.40 * ratio + 0.35 * Math.min(vouchW/5, 1) + 0.25 * tenure;
}
```

## Contract Skeleton

```solidity
contract TrustnetRegistry {
  mapping(bytes32 => CommitmentRecord) public commitments;
  mapping(bytes32 => VouchRecord) public vouches;

  event CommitmentCreated(bytes32 id, address maker, string context);
  event VouchCreated(bytes32 id, address voucher, address target);
}
```

## Key Exchange

```javascript
import { secp256k1 } from '@noble/secp256k1';
import { hkdf } from '@noble/hashes/hkdf';
import { sha256 } from '@noble/hashes/sha256';

async function establishSession(theirPublicKey) {
  const myPrivKey = secp256k1.utils.randomPrivateKey();
  const myPubKey  = secp256k1.getPublicKey(myPrivKey);

  // ECDH shared secret
  const sharedPoint  = secp256k1.getSharedSecret(myPrivKey, theirPublicKey);
  const sharedSecret = sharedPoint.slice(1, 33); // x-coordinate

  // Derive AES key via HKDF
  const aesKey = hkdf(sha256, sharedSecret, undefined,
                      'P2PAIR-v1', 32);

  return { aesKey, myPubKey };
}

async function encrypt(plaintext, aesKey) {
  const nonce = crypto.getRandomValues(new Uint8Array(12));
  const key   = await crypto.subtle.importKey(
    'raw', aesKey, { name: 'AES-GCM' }, false, ['encrypt']);
  const ct    = await crypto.subtle.encrypt(
    { name:'AES-GCM', iv:nonce }, key,
    new TextEncoder().encode(plaintext));
  return { nonce, ct };
}
```
